import {
  AgenticDeepReadItems,
  RetrievalModeItem,
} from '@/components/agentic-deepread-item';
import KnowledgeBaseItem from '@/components/knowledge-base-item';
import Rerank from '@/components/rerank';
import SimilaritySlider from '@/components/similarity-slider';
import { TavilyItem } from '@/components/tavily-item';
import TopNItem from '@/components/top-n-item';
import { UseKnowledgeGraphItem } from '@/components/use-knowledge-graph-item';
import { RetrievalMode } from '@/constants/agentic-deepread';
import { useTranslate } from '@/hooks/common-hooks';
import type { FormProps } from 'antd';
import { Form, Input } from 'antd';
import { useEffect } from 'react';
import { IOperatorForm } from '../../interface';
import DynamicInputVariable from '../components/dynamic-input-variable';

type FieldType = {
  top_n?: number;
};

const onFinish: FormProps<FieldType>['onFinish'] = (values) => {
  console.log('Success:', values);
};

const onFinishFailed: FormProps<FieldType>['onFinishFailed'] = (errorInfo) => {
  console.log('Failed:', errorInfo);
};

const RetrievalForm = ({ onValuesChange, form, node }: IOperatorForm) => {
  const { t } = useTranslate('flow');
  const retrievalMode =
    Form.useWatch('retrieval_mode', form) ?? RetrievalMode.Naive;
  const isAgenticDeepRead = retrievalMode === RetrievalMode.AgenticDeepRead;

  useEffect(() => {
    form?.setFieldValue('use_kg', retrievalMode === RetrievalMode.Graph);
  }, [form, retrievalMode]);

  return (
    <Form
      name="basic"
      onFinish={onFinish}
      onFinishFailed={onFinishFailed}
      autoComplete="off"
      onValuesChange={onValuesChange}
      form={form}
      layout={'vertical'}
    >
      <DynamicInputVariable node={node}></DynamicInputVariable>
      {!isAgenticDeepRead && (
        <SimilaritySlider
          isTooltipShown
          vectorSimilarityWeightName="keywords_similarity_weight"
        ></SimilaritySlider>
      )}
      {!isAgenticDeepRead && <TopNItem></TopNItem>}
      <RetrievalModeItem filedName={'retrieval_mode'} />
      {isAgenticDeepRead && (
        <AgenticDeepReadItems baseName={'agentic_deepread'} />
      )}
      {!isAgenticDeepRead && <Rerank></Rerank>}
      {!isAgenticDeepRead && <TavilyItem name={'tavily_api_key'}></TavilyItem>}
      {!isAgenticDeepRead && (
        <UseKnowledgeGraphItem
          filedName={'use_kg'}
          disabled
        ></UseKnowledgeGraphItem>
      )}
      <KnowledgeBaseItem
        tooltipText={t('knowledgeBasesTip')}
      ></KnowledgeBaseItem>
      <DynamicInputVariable
        name={'kb_vars'}
        node={node}
        title={t('knowledgeBaseVars')}
      ></DynamicInputVariable>
      <Form.Item
        name={'empty_response'}
        label={t('emptyResponse', { keyPrefix: 'chat' })}
        tooltip={t('emptyResponseTip', { keyPrefix: 'chat' })}
      >
        <Input.TextArea placeholder="" rows={4} />
      </Form.Item>
    </Form>
  );
};

export default RetrievalForm;
